// Some portions generated by Claude
package org.eclipse.rdf4j.query.algebra.equivalence.internal;

import java.io.IOException;
import java.io.OutputStream;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.Locale;

import org.eclipse.rdf4j.query.algebra.TupleExpr;
import org.eclipse.rdf4j.query.algebra.equivalence.EvaluationCase;
import org.eclipse.rdf4j.query.algebra.json.TupleExprJsonWriteException;
import org.eclipse.rdf4j.query.algebra.json.TupleExprJsonWriter;
import org.eclipse.rdf4j.rio.RDFFormat;
import org.eclipse.rdf4j.rio.Rio;

/**
 * Persists every violation as a reproducible artifact under {@code target/equivalence-fuzz/}: both trees in the
 * rdf4j-tuple-expr JSON fixture format (promotable straight into src/test/resources), the witness dataset as N-Triples,
 * and a REPORT.md with the seed, mutator chain and a copy-paste repro command. Never throws — a broken artifact must
 * not mask the violation it describes.
 */
final class FuzzArtifactWriter {
	private final Path runDir;
	private int counter;

	FuzzArtifactWriter(Path baseDir, long seed) {
		this.runDir = baseDir.resolve("seed-" + seed);
	}

	synchronized void write(FuzzViolation violation, FuzzProfile profile) {
		try {
			Path dir = runDir.resolve(String.format("%03d-%s", ++counter,
					violation.invariant().name().toLowerCase(Locale.ROOT)));
			Files.createDirectories(dir);
			writeTree(dir, "original", violation.pair().original());
			writeTree(dir, "candidate", violation.pair().candidate());
			if (violation.witness() != null) {
				writeWitness(dir, violation.witness());
			}
			Files.writeString(dir.resolve("REPORT.md"), report(violation, profile), StandardCharsets.UTF_8);
		} catch (Exception e) {
			System.err.println("[fuzz] failed to persist artifact for " + violation.describe() + ": " + e);
		}
	}

	private void writeTree(Path dir, String name, TupleExpr tree) throws IOException {
		try (OutputStream out = Files.newOutputStream(dir.resolve(name + ".json"))) {
			new TupleExprJsonWriter().write(tree, out);
		} catch (TupleExprJsonWriteException e) {
			Files.writeString(dir.resolve(name + ".txt"), tree.toString(), StandardCharsets.UTF_8);
		}
	}

	private void writeWitness(Path dir, EvaluationCase witness) throws IOException {
		try (OutputStream out = Files.newOutputStream(dir.resolve("witness-case.nt"))) {
			Rio.write(witness.getStatements(), out, RDFFormat.NTRIPLES);
		}
	}

	private String report(FuzzViolation violation, FuzzProfile profile) {
		StringBuilder report = new StringBuilder();
		report.append("# ")
				.append(violation.invariant())
				.append('\n')
				.append('\n')
				.append(violation.describe())
				.append('\n')
				.append('\n')
				.append("- profile: ")
				.append(profile.label())
				.append(" (target=")
				.append(profile.target())
				.append(", mode=")
				.append(profile.mode())
				.append(", contextMode=")
				.append(profile.contextMode())
				.append(")\n")
				.append("- pair seed: ")
				.append(violation.pair().seed())
				.append('\n')
				.append("- mutator chain: ")
				.append(violation.pair().mutatorChain())
				.append('\n');
		if (violation.witness() != null) {
			report.append("- witness case: ")
					.append(violation.witness().getLabel())
					.append(" (initial bindings: ")
					.append(violation.witness().getInitialBindings())
					.append(")\n");
		}
		report.append('\n')
				.append("Reproduce with:\n\n")
				.append("    mvn -o -Dmaven.repo.local=.m2_repo -pl core/queryalgebra/equivalence test \\\n")
				.append("        -P slowTestsOnly,\\!skipSlowTests -Dtest=FuzzSoakTest \\\n")
				.append("        -Dequivalence.fuzz.seed=")
				.append(violation.pair().seed())
				.append('\n');
		return report.toString();
	}
}
